function largestMultipleOfThree(digits) {
    digits.sort((a, b) => b - a);
    const sum = digits.reduce((a, b) => a + b, 0);

    if (sum % 3 === 0) {
        if (digits[digits.length - 1] === 0) return "0";
        return digits.join("");
    }

    let mod = new Array(3).fill(null).map(() => []);
    for (let digit of digits) {
        mod[digit % 3].push(digit);
    }

    if (sum % 3 === 1) {
        if (mod[1].length > 0) {
            mod[1].pop();
        } else {
            mod[2].pop(), mod[2].pop();
        }
    } else {
        if (mod[2].length > 0) {
            mod[2].pop();
        } else {
            mod[1].pop(), mod[1].pop();
        }
    }

    let result = mod.flat().join("");
    result = Array.from(result).sort((a, b) => b - a).join("");

    if (!result || result[0] === "0") {
        return "0";
    }

    return result;
}
```


    1. Sort the input array in descending order.
2. Calculate the sum of all digits.
3. If the sum is divisible by 3, return the joined digits as a string (or "0" if the last digit is 0).
4. Create a mod array where mod[i] contains digits with the remainder i when divided by 3.
5. If the remainder of the sum is 1:
    - Remove the smallest digit from mod[1], if not empty.
    - Otherwise, remove the two smallest digits from mod[2].
6. If the remainder of the sum is 2:
    - Remove the smallest digit from mod[2], if not empty.
    - Otherwise, remove the two smallest digits from mod[1].
7. Flatten the mod array and join its digits into a string. Sort the string in descending order.
8. Return the sorted string (or "0" if empty or starting with "0").

